// Copilot Draft Action handler (ADR-0067, ADR-0081, ADR-0147 Slice 1). The draft is
// generated by a genuine unbound internal_copilot agent turn over
// `POST /v1/agent:turn` (the LLM seam). Drafting requires a valid selected case (no
// drafting without a case); the result is a suggestion only — sending is a separate
// governed action.
//
// The `draft_generated` audit is recorded SERVER-SIDE by the agent:turn endpoint
// (#47, option i: it reuses the datastore audit writer, so the row lands in the
// Postgres `workbench_audit_log` the governed audit-log read consults). 0.0.4 S09
// deleted the in-memory mock path, so there is no second, write-only audit copy.
import { json, problem } from "../respond";
import { readJsonBody, readNonEmptyString } from "./deps";
import type {
  DraftChannel,
  HermesAgentClient,
} from "../../gateway/hermes-agent-client";
import type { HermesApiClient } from "../../gateway/hermes-api-client";
import { hermesErrorToProblem } from "../../gateway/hermes-error";

export type DraftAction = "draft_sms" | "draft_email" | "draft_internal_note";

const CHANNEL_BY_ACTION: Record<DraftAction, DraftChannel> = {
  draft_sms: "sms",
  draft_email: "email",
  draft_internal_note: "internal_note",
};

export async function handleDraftViaApi(
  req: Request,
  agent: HermesAgentClient,
  client: HermesApiClient,
  action: DraftAction,
): Promise<Response> {
  const body = await readJsonBody(req);
  const caseId = readNonEmptyString(body, "caseId");
  if (!caseId) return problem(400, "caseId is required");
  const prompt = readNonEmptyString(body, "prompt") ?? undefined;
  try {
    // 404: a draft needs a real case. A null read is a legitimate empty read
    // (ADR-0020) -> 404. The pre-read goes to the deterministic dispatch (the
    // datastore is the source of truth), mirroring the case-write path.
    const found = (await client.dispatch("toee_workbench_read", "get_case", {
      case_id: caseId,
    })) as { case?: unknown };
    if (!found || found.case == null) return problem(404, "case not found");

    const data = await agent.generateDraft({
      channel: CHANNEL_BY_ACTION[action],
      caseId,
      prompt,
    });
    // The agent's per-channel envelope IS the draft payload, passed through minus
    // `provenance` (governance metadata the textarea never binds). This covers all
    // three channel shapes — sms/email `{channel,...}`, email's `subject`, note's
    // `{kind,...}` — without per-channel branching.
    const { provenance: _provenance, ...draft } = data;
    return json({ draft });
  } catch (err) {
    return hermesErrorToProblem(err);
  }
}
